import React, { useState, useEffect } from 'react';

interface Book {
  id: number;
  title: string;
  author: string;
  isbn: string;
  price: number;
}

export function BookList() {
  const [books, setBooks] = useState<Book[]>([]);

  useEffect(() => {
    fetch('/api/books')
      .then(res => res.json())
      .then(setBooks);
  }, []);

  return (
    <div className="book-list">
      <h2>Bookstore</h2>
      {books.map(book => (
        <div key={book.id} className="book-card">
          <h3>{book.title}</h3>
          <p>{book.author} — ${book.price}</p>
        </div>
      ))}
    </div>
  );
}
